package org.apache.commons.lang;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.lang.steps",
    tags = "@LocaleUtils or not @Ignore"
)
public class CucumberTest {
    // This class serves as the JUnit test runner for Cucumber features
}

package org.apache.commons.lang.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.lang.LocaleUtils;
import java.util.Locale;
import java.util.Set;

import static org.junit.Assert.*;

public class StepDefs {
    private Set<Locale> firstCallResult;
    private Set<Locale> secondCallResult;
    private Set<Locale> actualResult;
    private Locale[] systemLocales;

    @Given("the system has a set of available locales")
    public void the_system_has_a_set_of_available_locales() {
        systemLocales = Locale.getAvailableLocales();
    }

    @When("a user calls LocaleUtils.availableLocaleSet() multiple times")
    public void a_user_calls_locale_utils_available_locale_set_multiple_times() {
        firstCallResult = LocaleUtils.availableLocaleSet();
        secondCallResult = LocaleUtils.availableLocaleSet();
    }

    @Then("all calls should return the exact same Set reference")
    public void all_calls_should_return_the_exact_same_set_reference() {
        assertSame("Multiple calls should return the same set reference", firstCallResult, secondCallResult);
    }

    @Then("the returned set should contain all locales from Locale.getAvailableLocales()")
    public void the_returned_set_should_contain_all_locales_from_locale_get_available_locales() {
        assertEquals("Set should contain all available locales", systemLocales.length, firstCallResult.size());

        for (Locale locale : systemLocales) {
            assertTrue("Set should contain locale: " + locale, firstCallResult.contains(locale));
        }
    }

    @Then("the returned set should be unmodifiable")
    public void the_returned_set_should_be_unmodifiable() {
        try {
            firstCallResult.add(Locale.ENGLISH);
            fail("Expected UnsupportedOperationException when trying to modify the set");
        } catch (UnsupportedOperationException e) {
            // Expected behavior
        }
    }

    @Given("multiple threads accessing LocaleUtils.availableLocaleSet() simultaneously")
    public void multiple_threads_accessing_locale_utils_available_locale_set_simultaneously() {
        systemLocales = Locale.getAvailableLocales();
    }

    @When("each thread calls LocaleUtils.availableLocaleSet()")
    public void each_thread_calls_locale_utils_available_locale_set() {
        // In this test, we're simulating the concurrent access behavior
        // by just making multiple calls
        firstCallResult = LocaleUtils.availableLocaleSet();
        secondCallResult = LocaleUtils.availableLocaleSet();
    }

    @Then("all threads should receive the same set reference once initialization is complete")
    public void all_threads_should_receive_the_same_set_reference_once_initialization_is_complete() {
        assertSame("All calls should return the same set reference", firstCallResult, secondCallResult);
    }

    @Then("no race conditions should occur during initialization")
    public void no_race_conditions_should_occur_during_initialization() {
        // This is tested by checking if the returned set is consistent
        assertNotNull("Set should not be null", firstCallResult);
        assertFalse("Set should not be empty", firstCallResult.isEmpty());
    }

    @Given("the system has a specific set of available locales")
    public void the_system_has_a_specific_set_of_available_locales() {
        systemLocales = Locale.getAvailableLocales();
    }

    @When("a user calls LocaleUtils.availableLocaleSet()")
    public void a_user_calls_locale_utils_available_locale_set() {
        actualResult = LocaleUtils.availableLocaleSet();
    }

    @Then("the returned set should contain exactly the same locales as Locale.getAvailableLocales()")
    public void the_returned_set_should_contain_exactly_the_same_locales_as_locale_get_available_locales() {
        assertEquals("Set should contain same number of locales", systemLocales.length, actualResult.size());

        for (Locale locale : systemLocales) {
            assertTrue("Set should contain locale: " + locale, actualResult.contains(locale));
        }
    }

    @Then("the set should be consistent across multiple calls")
    public void the_set_should_be_consistent_across_multiple_calls() {
        Set<Locale> anotherCallResult = LocaleUtils.availableLocaleSet();
        assertEquals("Set should be consistent across calls", actualResult.size(), anotherCallResult.size());
        assertTrue("Set contents should be the same", actualResult.equals(anotherCallResult));
        assertSame("Set reference should be the same", actualResult, anotherCallResult);
    }

    @Then("the set should be unmodifiable to prevent external modification")
    public void the_set_should_be_unmodifiable_to_prevent_external_modification() {
        try {
            actualResult.add(Locale.ENGLISH);
            fail("Expected UnsupportedOperationException when trying to modify the set");
        } catch (UnsupportedOperationException e) {
            // Expected behavior
        }
    }
}

